{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::collections::HashMap;
use std::sync::RwLock;

pub struct VectorDB {
    // Store vectors in a HashMap protected by RwLock for thread-safe access
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut db_vectors = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            db_vectors.insert(id, vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        // Brute-force search: compute distance to all vectors
        let mut results: Vec<SearchResult> = vectors
            .iter()
            .map(|(id, vector)| {
                let distance = l2_distance(query, vector);
                SearchResult {
                    id: *id,
                    distance,
                }
            })
            .collect();

        // Sort by distance (ascending - closest first)
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        // Return top-k results
        results.truncate(top_k as usize);
        results
    }
}
"}

{"path": "src/distance.rs", "content": "#[cfg(target_arch = "x86_64")]
use std::arch::x86_64::*;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
#[inline]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm256_setzero_ps();
    let len = a.len();
    let chunks = len / 8;

    for i in 0..chunks {
        let idx = i * 8;
        let a_vec = _mm256_loadu_ps(a.as_ptr().add(idx));
        let b_vec = _mm256_loadu_ps(b.as_ptr().add(idx));
        let diff = _mm256_sub_ps(a_vec, b_vec);
        sum = _mm256_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum
    let mut result = [0.0f32; 8];
    _mm256_storeu_ps(result.as_mut_ptr(), sum);
    let mut total = result.iter().sum::<f32>();

    // Handle remaining elements
    for i in (chunks * 8)..len {
        let diff = a[i] - b[i];
        total += diff * diff;
    }

    (total as f64).sqrt()
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();
    let len = a.len();
    let chunks = len / 16;

    for i in 0..chunks {
        let idx = i * 16;
        let a_vec = _mm512_loadu_ps(a.as_ptr().add(idx));
        let b_vec = _mm512_loadu_ps(b.as_ptr().add(idx));
        let diff = _mm512_sub_ps(a_vec, b_vec);
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum
    let total = _mm512_reduce_add_ps(sum);

    // Handle remaining elements (for 128-dim, there are no remainders)
    let mut remainder = 0.0f32;
    for i in (chunks * 16)..len {
        let diff = a[i] - b[i];
        remainder += diff * diff;
    }

    ((total + remainder) as f64).sqrt()
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            unsafe { l2_distance_avx512(a, b) }
        } else if is_x86_feature_detected!("avx2") {
            unsafe { l2_distance_avx2(a, b) }
        } else {
            l2_distance_scalar(a, b)
        }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        l2_distance_scalar(a, b)
    }
}

#[inline]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let diff = x - y;
            (diff * diff) as f64
        })
        .sum::<f64>()
        .sqrt()
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

pub struct VectorDB {
    // Store vectors as a flat array for better cache locality
    // Each vector is 128 floats
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.push((id, vector));
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vectors = self.vectors.write().unwrap();
        let count = new_vectors.len();
        vectors.extend(new_vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();
        let k = top_k as usize;

        // Parallel distance computation using rayon
        let mut results: Vec<SearchResult> = vectors
            .par_iter()
            .map(|(id, vector)| {
                let distance = l2_distance(query, vector);
                SearchResult {
                    id: *id,
                    distance,
                }
            })
            .collect();

        // Partial sort to get top-k (faster than full sort)
        if results.len() > k {
            results.select_nth_unstable_by(k, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap()
            });
            results.truncate(k);
        }

        // Sort the top-k by distance (ascending - closest first)
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

pub struct VectorDB {
    // Store vectors in contiguous memory with aligned layout
    // ids and vectors stored separately for better cache access patterns
    data: RwLock<VectorData>,
}

struct VectorData {
    ids: Vec<u64>,
    vectors: Vec<f32>, // Flattened: 128 floats per vector
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorData {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = new_vectors.len();

        data.ids.reserve(count);
        data.vectors.reserve(count * 128);

        for (id, vector) in new_vectors {
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }

        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;
        let num_vectors = data.ids.len();

        if num_vectors == 0 {
            return Vec::new();
        }

        // Parallel distance computation using rayon with chunks
        let chunk_size = (num_vectors + 3) / 4; // Divide into 4 chunks for 4 cores

        let mut results: Vec<SearchResult> = (0..num_vectors)
            .into_par_iter()
            .with_min_len(chunk_size)
            .map(|i| {
                let vector_start = i * 128;
                let vector = &data.vectors[vector_start..vector_start + 128];
                let distance = l2_distance(query, vector);
                SearchResult {
                    id: data.ids[i],
                    distance,
                }
            })
            .collect();

        // Partial sort to get top-k (faster than full sort)
        if results.len() > k {
            results.select_nth_unstable_by(k, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap()
            });
            results.truncate(k);
        }

        // Sort the top-k by distance (ascending - closest first)
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

const NUM_CLUSTERS: usize = 256;
const PROBE_CLUSTERS: usize = 16; // Number of clusters to search

pub struct VectorDB {
    data: RwLock<VectorData>,
}

struct VectorData {
    ids: Vec<u64>,
    vectors: Vec<f32>, // Flattened: 128 floats per vector
    // IVF index
    centroids: Vec<f32>, // NUM_CLUSTERS * 128 floats
    inverted_lists: Vec<Vec<usize>>, // Vector indices for each cluster
    indexed: bool,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorData {
                ids: Vec::new(),
                vectors: Vec::new(),
                centroids: Vec::new(),
                inverted_lists: vec![Vec::new(); NUM_CLUSTERS],
                indexed: false,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend_from_slice(&vector);
        data.indexed = false; // Mark index as stale
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = new_vectors.len();

        data.ids.reserve(count);
        data.vectors.reserve(count * 128);

        for (id, vector) in new_vectors {
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }

        data.indexed = false; // Mark index as stale
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let mut data = self.data.write().unwrap();
        let k = top_k as usize;
        let num_vectors = data.ids.len();

        if num_vectors == 0 {
            return Vec::new();
        }

        // Build index if not already built
        if !data.indexed {
            build_ivf_index(&mut data);
        }

        // Find nearest centroids to query
        let nearest_clusters = find_nearest_centroids(query, &data.centroids, PROBE_CLUSTERS.min(NUM_CLUSTERS));

        // Search only in the nearest clusters
        let mut results = Vec::new();
        for cluster_id in nearest_clusters {
            let indices = &data.inverted_lists[cluster_id];
            for &i in indices {
                let vector_start = i * 128;
                let vector = &data.vectors[vector_start..vector_start + 128];
                let distance = l2_distance(query, vector);
                results.push(SearchResult {
                    id: data.ids[i],
                    distance,
                });
            }
        }

        // Partial sort to get top-k
        if results.len() > k {
            results.select_nth_unstable_by(k, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap()
            });
            results.truncate(k);
        }

        // Sort the top-k by distance
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}

fn build_ivf_index(data: &mut VectorData) {
    let num_vectors = data.ids.len();
    if num_vectors == 0 {
        return;
    }

    // Initialize centroids using k-means++ initialization
    data.centroids = vec![0.0; NUM_CLUSTERS * 128];

    // Simple initialization: pick evenly spaced vectors as initial centroids
    for i in 0..NUM_CLUSTERS {
        let idx = (i * num_vectors) / NUM_CLUSTERS;
        let src_start = idx * 128;
        let dst_start = i * 128;
        data.centroids[dst_start..dst_start + 128]
            .copy_from_slice(&data.vectors[src_start..src_start + 128]);
    }

    // Run k-means for a few iterations
    for _ in 0..5 {
        // Clear inverted lists
        for list in &mut data.inverted_lists {
            list.clear();
        }

        // Assign each vector to nearest centroid
        for i in 0..num_vectors {
            let vector_start = i * 128;
            let vector = &data.vectors[vector_start..vector_start + 128];

            let mut min_dist = f64::MAX;
            let mut best_cluster = 0;

            for c in 0..NUM_CLUSTERS {
                let centroid_start = c * 128;
                let centroid = &data.centroids[centroid_start..centroid_start + 128];
                let dist = l2_distance(vector, centroid);
                if dist < min_dist {
                    min_dist = dist;
                    best_cluster = c;
                }
            }

            data.inverted_lists[best_cluster].push(i);
        }

        // Update centroids
        for c in 0..NUM_CLUSTERS {
            let indices = &data.inverted_lists[c];
            if indices.is_empty() {
                continue;
            }

            let centroid_start = c * 128;
            let centroid = &mut data.centroids[centroid_start..centroid_start + 128];
            centroid.fill(0.0);

            for &i in indices {
                let vector_start = i * 128;
                let vector = &data.vectors[vector_start..vector_start + 128];
                for d in 0..128 {
                    centroid[d] += vector[d];
                }
            }

            let count = indices.len() as f32;
            for d in 0..128 {
                centroid[d] /= count;
            }
        }
    }

    data.indexed = true;
}

fn find_nearest_centroids(query: &[f32], centroids: &[f32], n: usize) -> Vec<usize> {
    let num_centroids = centroids.len() / 128;

    let mut dists: Vec<(usize, f64)> = (0..num_centroids)
        .map(|i| {
            let centroid_start = i * 128;
            let centroid = &centroids[centroid_start..centroid_start + 128];
            let dist = l2_distance(query, centroid);
            (i, dist)
        })
        .collect();

    dists.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
    dists.truncate(n);
    dists.into_iter().map(|(i, _)| i).collect()
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

const NUM_CLUSTERS: usize = 512;
const PROBE_CLUSTERS: usize = 32; // Number of clusters to search

pub struct VectorDB {
    data: RwLock<VectorData>,
}

struct VectorData {
    ids: Vec<u64>,
    vectors: Vec<f32>, // Flattened: 128 floats per vector
    // IVF index
    centroids: Vec<f32>, // NUM_CLUSTERS * 128 floats
    inverted_lists: Vec<Vec<usize>>, // Vector indices for each cluster
    indexed: bool,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(VectorData {
                ids: Vec::new(),
                vectors: Vec::new(),
                centroids: Vec::new(),
                inverted_lists: vec![Vec::new(); NUM_CLUSTERS],
                indexed: false,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend_from_slice(&vector);
        data.indexed = false;
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = new_vectors.len();

        data.ids.reserve(count);
        data.vectors.reserve(count * 128);

        for (id, vector) in new_vectors {
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }

        data.indexed = false;
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let mut data = self.data.write().unwrap();
        let k = top_k as usize;
        let num_vectors = data.ids.len();

        if num_vectors == 0 {
            return Vec::new();
        }

        // Build index if not already built
        if !data.indexed {
            build_ivf_index(&mut data);
        }

        // Find nearest centroids to query
        let nearest_clusters = find_nearest_centroids(query, &data.centroids, PROBE_CLUSTERS.min(NUM_CLUSTERS));

        // Collect candidate indices from nearest clusters
        let mut candidate_indices = Vec::new();
        for cluster_id in nearest_clusters {
            candidate_indices.extend_from_slice(&data.inverted_lists[cluster_id]);
        }

        // Parallel distance computation for candidates
        let mut results: Vec<SearchResult> = candidate_indices
            .par_iter()
            .map(|&i| {
                let vector_start = i * 128;
                let vector = &data.vectors[vector_start..vector_start + 128];
                let distance = l2_distance(query, vector);
                SearchResult {
                    id: data.ids[i],
                    distance,
                }
            })
            .collect();

        // Partial sort to get top-k
        if results.len() > k {
            results.select_nth_unstable_by(k, |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap()
            });
            results.truncate(k);
        }

        // Sort the top-k by distance
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}

fn build_ivf_index(data: &mut VectorData) {
    let num_vectors = data.ids.len();
    if num_vectors == 0 {
        return;
    }

    // Initialize centroids
    data.centroids = vec![0.0; NUM_CLUSTERS * 128];

    // Simple initialization: pick evenly spaced vectors as initial centroids
    for i in 0..NUM_CLUSTERS.min(num_vectors) {
        let idx = (i * num_vectors) / NUM_CLUSTERS;
        let src_start = idx * 128;
        let dst_start = i * 128;
        data.centroids[dst_start..dst_start + 128]
            .copy_from_slice(&data.vectors[src_start..src_start + 128]);
    }

    // Run k-means for a few iterations with parallel assignment
    for _ in 0..5 {
        // Clear inverted lists
        for list in &mut data.inverted_lists {
            list.clear();
        }

        // Parallel assignment to clusters
        let assignments: Vec<usize> = (0..num_vectors)
            .into_par_iter()
            .map(|i| {
                let vector_start = i * 128;
                let vector = &data.vectors[vector_start..vector_start + 128];

                let mut min_dist = f64::MAX;
                let mut best_cluster = 0;

                for c in 0..NUM_CLUSTERS {
                    let centroid_start = c * 128;
                    let centroid = &data.centroids[centroid_start..centroid_start + 128];
                    let dist = l2_distance(vector, centroid);
                    if dist < min_dist {
                        min_dist = dist;
                        best_cluster = c;
                    }
                }

                best_cluster
            })
            .collect();

        // Build inverted lists from assignments
        for (i, &cluster) in assignments.iter().enumerate() {
            data.inverted_lists[cluster].push(i);
        }

        // Update centroids in parallel
        let new_centroids: Vec<f32> = (0..NUM_CLUSTERS)
            .into_par_iter()
            .flat_map(|c| {
                let indices = &data.inverted_lists[c];
                let mut centroid = vec![0.0f32; 128];

                if !indices.is_empty() {
                    for &i in indices {
                        let vector_start = i * 128;
                        let vector = &data.vectors[vector_start..vector_start + 128];
                        for d in 0..128 {
                            centroid[d] += vector[d];
                        }
                    }

                    let count = indices.len() as f32;
                    for d in 0..128 {
                        centroid[d] /= count;
                    }
                } else {
                    // Keep old centroid if cluster is empty
                    let old_start = c * 128;
                    centroid.copy_from_slice(&data.centroids[old_start..old_start + 128]);
                }

                centroid
            })
            .collect();

        data.centroids = new_centroids;
    }

    data.indexed = true;
}

fn find_nearest_centroids(query: &[f32], centroids: &[f32], n: usize) -> Vec<usize> {
    let num_centroids = centroids.len() / 128;

