        let idx = (i * num_vectors) / NUM_CLUSTERS;
        let src_start = idx * 128;
        let dst_start = i * 128;
        data.centroids[dst_start..dst_start + 128]
            .copy_from_slice(&data.vectors[src_start..src_start + 128]);
    }

