use crate::api::*;
use crate::distance::l2_distance;
use std::collections::HashMap;
use std::sync::RwLock;

pub struct VectorDB {
    // Store vectors in a HashMap protected by RwLock for thread-safe access
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut db_vectors = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            db_vectors.insert(id, vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        // Brute-force search: compute distance to all vectors
        let mut results: Vec<SearchResult> = vectors
            .iter()
            .map(|(id, vector)| {
                let distance = l2_distance(query, vector);
                SearchResult {
                    id: *id,
                    distance,
                }
            })
            .collect();

        // Sort by distance (ascending - closest first)
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        // Return top-k results
        results.truncate(top_k as usize);
        results
    }
}

#[cfg(target_arch = "x86_64")]
use std::arch::x86_64::*;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
#[inline]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm256_setzero_ps();
    let len = a.len();
    let chunks = len / 8;

    for i in 0..chunks {
        let idx = i * 8;
        let a_vec = _mm256_loadu_ps(a.as_ptr().add(idx));
        let b_vec = _mm256_loadu_ps(b.as_ptr().add(idx));
        let diff = _mm256_sub_ps(a_vec, b_vec);
        sum = _mm256_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum
    let mut result = [0.0f32; 8];
    _mm256_storeu_ps(result.as_mut_ptr(), sum);
    let mut total = result.iter().sum::<f32>();

    // Handle remaining elements
    for i in (chunks * 8)..len {
        let diff = a[i] - b[i];
        total += diff * diff;
    }

    (total as f64).sqrt()
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();
    let len = a.len();
    let chunks = len / 16;

    for i in 0..chunks {
        let idx = i * 16;
        let a_vec = _mm512_loadu_ps(a.as_ptr().add(idx));
        let b_vec = _mm512_loadu_ps(b.as_ptr().add(idx));
        let diff = _mm512_sub_ps(a_vec, b_vec);
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum
    let total = _mm512_reduce_add_ps(sum);

    // Handle remaining elements (for 128-dim, there are no remainders)
    let mut remainder = 0.0f32;
    for i in (chunks * 16)..len {
        let diff = a[i] - b[i];
        remainder += diff * diff;
    }

    ((total + remainder) as f64).sqrt()
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            unsafe { l2_distance_avx512(a, b) }
        } else if is_x86_feature_detected!("avx2") {
            unsafe { l2_distance_avx2(a, b) }
        } else {
            l2_distance_scalar(a, b)
        }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        l2_distance_scalar(a, b)
    }
}

#[inline]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let diff = x - y;
            (diff * diff) as f64
        })
        .sum::<f64>()
        .sqrt()
}

